    const optionalEdges = [];
    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if must edges form a cycle (using Union-Find)
    const parent = new Array(n).fill(-1);
    function find(u) {
        if (parent[u] === -1) return u;
        parent[u] = find(parent[u]);
        return parent[u];
    }

    let mustCount = 0;
    for (const [u, v, s] of mustEdges) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return -1; // cycle detected
        }
        parent[rootU] = rootV;
        mustCount++;
    }

    // Now, we need to select (n-1 - mustCount) edges from optionalEdges
    // We want to maximize the minimal strength, so we can use binary search
    // to find the maximum possible minimal strength.

    let low = 1;
    let high = 1e5;
    let answer = -1;

    // Binary search over possible minimal strengths
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(mid, [...parent], optionalEdges, n, mustCount, k)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

function isPossible(minStrength, parent, optionalEdges, n, mustCount, k) {
    // We need to select (n-1 - mustCount) edges from optionalEdges
    // such that all edges have strength >= minStrength (possibly upgraded)
    // and we can use up to k upgrades.

    function find(u, parent) {
        if (parent[u] === -1) return u;
        parent[u] = find(parent[u], parent);
        return parent[u];
    }

    // Sort optional edges by their maximum possible strength (after possible upgrade)
    const edges = optionalEdges.map(([u, v, s]) => {
        const maxS = s * 2;
        return { u, v, s, maxS };
    }).filter(edge => edge.maxS >= minStrength);

    // Sort edges by their original strength (ascending) to use upgrades efficiently
    edges.sort((a, b) => {
        // Prefer edges that can reach minStrength with minimal upgrades
        const aCanUseOriginal = a.s >= minStrength;
        const bCanUseOriginal = b.s >= minStrength;
        if (aCanUseOriginal && bCanUseOriginal) {
            return a.s - b.s;
        } else if (aCanUseOriginal) {
            return -1;
        } else if (bCanUseOriginal) {
            return 1;
        } else {
            return (a.maxS - minStrength) - (b.maxS - minStrength);
        }
    });

    let usedK = 0;
    let selectedEdges = 0;
    const neededEdges = n - 1 - mustCount;

    for (const edge of edges) {
        if (selectedEdges >= neededEdges) break;

        const { u, v, s, maxS } = edge;
        const rootU = find(u, parent);
        const rootV = find(v, parent);
        if (rootU === rootV) continue;

        // Check if we can use this edge with strength >= minStrength
        let currentS = s;
        if (s < minStrength) {
            if (maxS >= minStrength && usedK < k) {
                currentS = maxS;
                usedK++;
            } else {
                continue;
            }
        }

        parent[rootU] = rootV;
        selectedEdges++;
    }

    return selectedEdges >= neededEdges;
}
